module RefModule(
        input           iCLK,
        input           iWRMLR,
        input  [7:0]    iMULHB,
        output [7:0]    oMULRG
    );reg [7:0]       unused_rMULRG = 8'h00;
    assign oMULRG = unused_rMULRG;

    always@(posedge iCLK) begin
        if(iWRMLR) begin
            unused_rMULRG <= iMULHB;
        end
        else begin
            unused_rMULRG <= unused_rMULRG;
        end
    end
endmodule
